tion>@foreach($units as $unit)<option value="{{ $unit->id }}" data-slug="{{ $unit->slug }}" @selected((string)old('scout_unit_id')===(string)$unit->id)>{{ $unit->name }} · {{ $unit->age_range }}</option>@endforeach</select>@error('scout_unit_id')<div class="error">{{ $message }}</div>@enderror</div><div><label class="label" id="phoneLabel" for="phone">Telephone</label><input id="phone" name="phone" type="text" class="input" value="{{ old('phone') }}">@error('phone')<div class="error">{{ $message }}</div>@enderror</div><div><label class="label" for="email">Email</label><input id="email" name="email" type="email" class="input" value="{{ old('email') }}">@error('email')<div class="error">{{ $message }}</div>@enderror</div><div class="full"><label class="label" for="address">Adresse</label><input id="address" name="address" type="text" class="input" value="{{ old('address') }}">@error('address')<div class="error">{{ $message }}</div>@enderror</div><div class="full"><label class="label" id="parentLabel" for="parent_name">Parent / tuteur</label><input id="parent_name" name="parent_name" type="text" class="input" value="{{ old('parent_name') }}">@error('parent_name')<div class="error">{{ $message }}</div>@enderror</div><div class="full"><label class="label" for="medical_notes">Informations medicales</label><textarea id="medical_notes" name="medical_notes" class="textarea">{{ old('medical_notes') }}</textarea>@error('medical_notes')<div class="error">{{ $message }}</div>@enderror</div><div class="full"><label class="label" for="motivation">Motivation</label><textarea id="motivation" name="motivation" class="textarea">{{ old('motivation') }}</textarea>@error('motivation')<div class="error">{{ $message }}</div>@enderror</div><div class="full" style="padding-top:.4rem;"><button type="submit" class="btn-primary"><i class="fa-solid fa-fleur-de-lis"></i><span>Soumettre mon inscription</span></button></div></div></form></div></div></section>

