<!-- Gallery Modal -->
<div id="galleryModal" class="gallery-modal" style="display: none;">
    <div class="gallery-modal-content">
        <span class="gallery-modal-close" onclick="closeGalleryModal()">&times;</span>
        <div class="gallery-modal-media">
            <img id="modalImage" src="" alt="" style="display: none;">
            <video id="modalVideo" controls style="display: none;"></video>
        </div>
        <div class="gallery-modal-caption">
            <h3 id="modalTitle"></h3>
        </div>
    </div>
</div>

<script>
const navToggle=document.getElementById('navToggle'),mobileMenu=document.getElementById('mobileMenu'),birthDate=document.getElementById('birth_date'),unitSelect=document.getElementById('scout_unit_id'),phoneLabel=document.getElementById('phoneLabel'),parentLabel=document.getElementById('parentLabel'),unitSuggestion=document.getElementById('unitSuggestion');navToggle?.addEventListener('click',()=>mobileMenu.classList.toggle('open'));document.querySelectorAll('.mobile a').forEach(link=>link.addEventListener('click',()=>mobileMenu.classList.remove('open')));function updateRequirements(){const selected=unitSelect.options[unitSelect.selectedIndex],slug=selected?.dataset?.slug||'';phoneLabel.textContent=['route','amical'].includes(slug)?'Telephone *':'Telephone';parentLabel.textContent=['meute','troupe-f','troupe-m','grappe'].includes(slug)?'Parent / tuteur *':'Parent / tuteur'}function suggestUnit(){if(!birthDate.value){unitSuggestion.textContent="L'unite peut etre suggeree selon l'age.";return}const today=new Date(),dob=new Date(birthDate.value+'T00:00:00');let age=today.getFullYear()-dob.getFullYear();const gap=today.getMonth()-dob.getMonth();if(gap<0||(gap===0&&today.getDate()<dob.getDate()))age--;let text="L'unite peut etre suggeree selon l'age.";if(age>=6&&age<=11)text='Suggestion: Meute';else if(age>=12&&age<=15)text='Suggestion: Troupe F ou Troupe M';else if(age>=16&&age<=18)text='Suggestion: Grappe';else if(age>=19&&age<=23)text='Suggestion: Route';else if(age>23)text='Suggestion: Amical';else text="L'age minimum recommande est de 6 ans.";unitSuggestion.textContent=text}unitSelect?.addEventListener('change',updateRequirements);birthDate?.addEventListener('change',suggestUnit);updateRequirements();suggestUnit();

function openGalleryModal(mediaPath, title, mediaType) {
    const modal = document.getElementById('galleryModal');
    const modalImage = document.getElementById('modalImage');
    const modalVideo = document.getElementById('modalVideo');
    const modalTitle = document.getElementById('modalTitle');

    modalTitle.textContent = title;

    if (mediaType === 'video') {
        modalVideo.src = mediaPath;
        modalVideo.style.display = 'block';
        modalImage.style.display = 'none';
    } else {
        modalImage.src = mediaPath;
        modalImage.alt = title;
        modalImage.style.display = 'block';
        modalVideo.style.display = 'none';
    }

    modal.style.display = 'flex';
}

function closeGalleryModal() {
    const modal = document.getElementById('galleryModal');
    const modalVideo = document.getElementById('modalVideo');
    
    modal.style.display = 'none';
    modalVideo.pause();
    modalVideo.src = '';
}

// Close modal when clicking outside
document.addEventListener('DOMContentLoaded', function() {
    const modal = document.getElementById('galleryModal');
    modal.addEventListener('click', function(event) {
        if (event.target === modal) {
            closeGalleryModal();
        }
    });
});
</script>
</body>
